        idx += 3;

        if (opType == 1) {
            cache.put(key, value);
        } else if (opType == 2) {
            resultSum += cache.get(key);
        }
    }

    return resultSum;
}

using System.Collections.Generic;

public class LruCache
{
    private class Node
    {
        public int Key;
        public int Value;
        public Node Prev;
        public Node Next;

        public Node(int key, int value)
        {
            Key = key;
            Value = value;
        }
    }

    private readonly int _capacity;
    private readonly Dictionary<int, Node> _map;
    private readonly Node _head;
    private readonly Node _tail;

    private LruCache(int capacity)
    {
        _capacity = capacity;
        _map = new Dictionary<int, Node>();
        _head = new Node(0, 0);
        _tail = new Node(0, 0);
        _head.Next = _tail;
        _tail.Prev = _head;
    }

    private void RemoveNode(Node node)
    {
        node.Prev.Next = node.Next;
        node.Next.Prev = node.Prev;
    }

    private void AddToHead(Node node)
    {
        node.Next = _head.Next;
        node.Prev = _head;
        _head.Next.Prev = node;
        _head.Next = node;
    }

    private int Get(int key)
    {
        if (_map.TryGetValue(key, out Node node))
        {
            RemoveNode(node);
            AddToHead(node);
            return node.Value;
        }
        return -1;
    }

    private void Put(int key, int value)
    {
        if (_map.TryGetValue(key, out Node node))
        {
            node.Value = value;
            RemoveNode(node);
            AddToHead(node);
        }
        else
        {
            if (_map.Count == _capacity)
            {
                Node lru = _tail.Prev;
                RemoveNode(lru);
                _map.Remove(lru.Key);
            }
            Node newNode = new Node(key, value);
            _map[key] = newNode;
            AddToHead(newNode);
        }
    }

    public static int LruCacheOps(int[] operations)
    {
        int capacity = operations[0];
        int opCount = operations[1];
        LruCache cache = new LruCache(capacity);
        int resultSum = 0;
        int idx = 2;

        for (int i = 0; i < opCount; i++)
        {
            int opType = operations[idx];
            int key = operations[idx + 1];
            int value = operations[idx + 2];
            idx += 3;

            if (opType == 1)
            {
                cache.Put(key, value);
            }
            else if (opType == 2)
            {
                resultSum += cache.Get(key);
            }
        }

        return resultSum;
    }
}

package lrucache

type node struct {
	key, value int
	prev, next *node
}

type lruCache struct {
	capacity int
	m        map[int]*node
	head     *node
	tail     *node
}

func newLRUCache(capacity int) *lruCache {
	head := &node{}
	tail := &node{}
	head.next = tail
	tail.prev = head
	return &lruCache{
		capacity: capacity,
		m:        make(map[int]*node),
		head:     head,
		tail:     tail,
	}
}

func (c *lruCache) removeNode(n *node) {
	n.prev.next = n.next
	n.next.prev = n.prev
}

func (c *lruCache) addToHead(n *node) {
	n.next = c.head.next
	n.prev = c.head
	c.head.next.prev = n
	c.head.next = n
}

func (c *lruCache) get(key int) int {
	if n, ok := c.m[key]; ok {
		c.removeNode(n)
		c.addToHead(n)
		return n.value
	}
	return -1
}

func (c *lruCache) put(key, value int) {
	if n, ok := c.m[key]; ok {
		n.value = value
		c.removeNode(n)
		c.addToHead(n)
	} else {
		if len(c.m) == c.capacity {
			lru := c.tail.prev
			c.removeNode(lru)
			delete(c.m, lru.key)
		}
		n := &node{key: key, value: value}
		c.m[key] = n
		c.addToHead(n)
	}
}

// LruCache processes a sequence of LRU cache operations encoded as integers.
// Returns the sum of all get results (-1 for misses).
func LruCache(operations []int) int {
	capacity := operations[0]
	opCount := operations[1]
	cache := newLRUCache(capacity)
	resultSum := 0
	idx := 2

	for i := 0; i < opCount; i++ {
		opType := operations[idx]
		key := operations[idx+1]
		value := operations[idx+2]
		idx += 3

		if opType == 1 {
			cache.put(key, value)
		} else if opType == 2 {
			resultSum += cache.get(key)
		}
	}

	return resultSum
}

import java.util.HashMap;
import java.util.Map;

public class LruCache {

    private static class Node {
        int key, value;
        Node prev, next;

        Node(int key, int value) {
            this.key = key;
            this.value = value;
        }
    }

    private final int capacity;
    private final Map<Integer, Node> map;
    private final Node head;
    private final Node tail;

    private LruCache(int capacity) {
        this.capacity = capacity;
        this.map = new HashMap<>();
        this.head = new Node(0, 0);
        this.tail = new Node(0, 0);
        head.next = tail;
        tail.prev = head;
    }

    private void remove(Node node) {
        node.prev.next = node.next;
        node.next.prev = node.prev;
    }

    private void addToHead(Node node) {
        node.next = head.next;
        node.prev = head;
        head.next.prev = node;
        head.next = node;
    }

    private int get(int key) {
        if (map.containsKey(key)) {
            Node node = map.get(key);
            remove(node);
            addToHead(node);
            return node.value;
        }
        return -1;
    }

    private void put(int key, int value) {
        if (map.containsKey(key)) {
            Node node = map.get(key);
            node.value = value;
            remove(node);
            addToHead(node);
        } else {
            if (map.size() == capacity) {
                Node lru = tail.prev;
                remove(lru);
                map.remove(lru.key);
            }
            Node node = new Node(key, value);
            map.put(key, node);
            addToHead(node);
        }
    }

    public static int lruCache(int[] operations) {
        int capacity = operations[0];
        int opCount = operations[1];
        LruCache cache = new LruCache(capacity);
        int resultSum = 0;
        int idx = 2;

        for (int i = 0; i < opCount; i++) {
            int opType = operations[idx];
            int key = operations[idx + 1];
            int value = operations[idx + 2];
            idx += 3;

            if (opType == 1) {
                cache.put(key, value);
            } else if (opType == 2) {
                resultSum += cache.get(key);
            }
        }

        return resultSum;
    }
}

private class LruNode(var key: Int, var value: Int) {
