}

private class LruCacheImpl(private val capacity: Int) {
    private val map = HashMap<Int, LruNode>()
    private val head = LruNode(0, 0)
    private val tail = LruNode(0, 0)

    init {
        head.next = tail
        tail.prev = head
    }

    private fun removeNode(node: LruNode) {
        node.prev!!.next = node.next
        node.next!!.prev = node.prev
    }

    private fun addToHead(node: LruNode) {
        node.next = head.next
        node.prev = head
        head.next!!.prev = node
        head.next = node
    }

    fun get(key: Int): Int {
        val node = map[key] ?: return -1
        removeNode(node)
        addToHead(node)
        return node.value
    }

    fun put(key: Int, value: Int) {
        val existing = map[key]
        if (existing != null) {
            existing.value = value
            removeNode(existing)
            addToHead(existing)
        } else {
            if (map.size == capacity) {
                val lru = tail.prev!!
                removeNode(lru)
                map.remove(lru.key)
            }
            val node = LruNode(key, value)
            map[key] = node
            addToHead(node)
        }
    }
}

