use std::collections::HashMap;

struct Node {
    key: i32,
    value: i32,
    prev: usize,
    next: usize,
}

struct LruCacheImpl {
    nodes: Vec<Node>,
    map: HashMap<i32, usize>,
    head: usize,
    tail: usize,
    capacity: usize,
}

impl LruCacheImpl {
    fn new(capacity: usize) -> Self {
        let mut nodes = Vec::new();
        nodes.push(Node { key: 0, value: 0, prev: 0, next: 1 }); // head sentinel
        nodes.push(Node { key: 0, value: 0, prev: 0, next: 1 }); // tail sentinel
        LruCacheImpl {
            nodes,
            map: HashMap::new(),
            head: 0,
            tail: 1,
            capacity,
        }
    }

    fn remove_node(&mut self, idx: usize) {
        let prev = self.nodes[idx].prev;
        let next = self.nodes[idx].next;
        self.nodes[prev].next = next;
        self.nodes[next].prev = prev;
    }

    fn add_to_head(&mut self, idx: usize) {
        let head_next = self.nodes[self.head].next;
        self.nodes[idx].next = head_next;
        self.nodes[idx].prev = self.head;
        self.nodes[head_next].prev = idx;
        self.nodes[self.head].next = idx;
    }

    fn get(&mut self, key: i32) -> i32 {
        if let Some(&idx) = self.map.get(&key) {
            self.remove_node(idx);
            self.add_to_head(idx);
            self.nodes[idx].value
        } else {
            -1
        }
    }

    fn put(&mut self, key: i32, value: i32) {
        if let Some(&idx) = self.map.get(&key) {
            self.nodes[idx].value = value;
            self.remove_node(idx);
            self.add_to_head(idx);
        } else {
            if self.map.len() == self.capacity {
                let lru_idx = self.nodes[self.tail].prev;
                let lru_key = self.nodes[lru_idx].key;
                self.remove_node(lru_idx);
                self.map.remove(&lru_key);
                // Reuse the node
                self.nodes[lru_idx].key = key;
                self.nodes[lru_idx].value = value;
                self.map.insert(key, lru_idx);
                self.add_to_head(lru_idx);
            } else {
                let idx = self.nodes.len();
                self.nodes.push(Node { key, value, prev: 0, next: 0 });
                self.map.insert(key, idx);
                self.add_to_head(idx);
            }
        }
    }
}

pub fn lru_cache(operations: &[i32]) -> i32 {
    let capacity = operations[0] as usize;
    let op_count = operations[1] as usize;
    let mut cache = LruCacheImpl::new(capacity);
    let mut result_sum: i32 = 0;
    let mut idx = 2;

    for _ in 0..op_count {
        let op_type = operations[idx];
        let key = operations[idx + 1];
        let value = operations[idx + 2];
        idx += 3;

        if op_type == 1 {
            cache.put(key, value);
        } else if op_type == 2 {
            result_sum += cache.get(key);
        }
    }

    result_sum
}

import scala.collection.mutable

object LruCache {

  private class Node(var key: Int, var value: Int) {
    var prev: Node = _
    var next: Node = _
  }

  private class LruCacheImpl(capacity: Int) {
    private val map = mutable.HashMap[Int, Node]()
    private val head = new Node(0, 0)
    private val tail = new Node(0, 0)
    head.next = tail
    tail.prev = head

    private def removeNode(node: Node): Unit = {
      node.prev.next = node.next
      node.next.prev = node.prev
    }

    private def addToHead(node: Node): Unit = {
      node.next = head.next
      node.prev = head
      head.next.prev = node
      head.next = node
    }

    def get(key: Int): Int = {
      map.get(key) match {
        case Some(node) =>
          removeNode(node)
          addToHead(node)
          node.value
        case None => -1
      }
    }

    def put(key: Int, value: Int): Unit = {
      map.get(key) match {
        case Some(node) =>
          node.value = value
          removeNode(node)
          addToHead(node)
        case None =>
          if (map.size == capacity) {
            val lru = tail.prev
            removeNode(lru)
            map.remove(lru.key)
          }
          val node = new Node(key, value)
          map(key) = node
          addToHead(node)
      }
    }
  }

  def lruCache(operations: Array[Int]): Int = {
    val capacity = operations(0)
    val opCount = operations(1)
    val cache = new LruCacheImpl(capacity)
    var resultSum = 0
    var idx = 2

    for (_ <- 0 until opCount) {
      val opType = operations(idx)
      val key = operations(idx + 1)
      val value = operations(idx + 2)
      idx += 3

      if (opType == 1) {
        cache.put(key, value)
      } else if (opType == 2) {
        resultSum += cache.get(key)
      }
    }

    resultSum
  }
}

private class LruNode {
    var key: Int
    var value: Int
    var prev: LruNode?
    var next: LruNode?

    init(_ key: Int, _ value: Int) {
        self.key = key
        self.value = value
    }
}

private class LruCacheImpl {
    private let capacity: Int
    private var map: [Int: LruNode] = [:]
    private let head = LruNode(0, 0)
    private let tail = LruNode(0, 0)

    init(_ capacity: Int) {
        self.capacity = capacity
        head.next = tail
        tail.prev = head
    }

    private func removeNode(_ node: LruNode) {
        node.prev?.next = node.next
        node.next?.prev = node.prev
    }

    private func addToHead(_ node: LruNode) {
        node.next = head.next
        node.prev = head
        head.next?.prev = node
        head.next = node
    }

    func get(_ key: Int) -> Int {
        guard let node = map[key] else { return -1 }
        removeNode(node)
        addToHead(node)
        return node.value
    }

    func put(_ key: Int, _ value: Int) {
        if let existing = map[key] {
            existing.value = value
            removeNode(existing)
            addToHead(existing)
        } else {
            if map.count == capacity {
                let lru = tail.prev!
                removeNode(lru)
                map.removeValue(forKey: lru.key)
            }
            let node = LruNode(key, value)
            map[key] = node
            addToHead(node)
        }
    }
}

func lruCache(_ operations: [Int]) -> Int {
    let capacity = operations[0]
    let opCount = operations[1]
    let cache = LruCacheImpl(capacity)
    var resultSum = 0
    var idx = 2

    for _ in 0..<opCount {
        let opType = operations[idx]
        let key = operations[idx + 1]
        let value = operations[idx + 2]
        idx += 3

        if opType == 1 {
            cache.put(key, value)
        } else if opType == 2 {
            resultSum += cache.get(key)
        }
    }

    return resultSum
}

class LruNode {
    key: number;
    value: number;
    prev: LruNode | null = null;
    next: LruNode | null = null;

    constructor(key: number, value: number) {
        this.key = key;
        this.value = value;
    }
}

class LruCacheImpl {
    private capacity: number;
    private map: Map<number, LruNode>;
    private head: LruNode;
    private tail: LruNode;

    constructor(capacity: number) {
        this.capacity = capacity;
        this.map = new Map();
        this.head = new LruNode(0, 0);
        this.tail = new LruNode(0, 0);
        this.head.next = this.tail;
        this.tail.prev = this.head;
    }

    private remove(node: LruNode): void {
        node.prev!.next = node.next;
        node.next!.prev = node.prev;
    }

    private addToHead(node: LruNode): void {
        node.next = this.head.next;
        node.prev = this.head;
        this.head.next!.prev = node;
        this.head.next = node;
    }

    get(key: number): number {
        if (this.map.has(key)) {
            const node = this.map.get(key)!;
            this.remove(node);
            this.addToHead(node);
            return node.value;
        }
        return -1;
    }

    put(key: number, value: number): void {
        if (this.map.has(key)) {
            const node = this.map.get(key)!;
            node.value = value;
            this.remove(node);
            this.addToHead(node);
        } else {
            if (this.map.size === this.capacity) {
                const lru = this.tail.prev!;
                this.remove(lru);
                this.map.delete(lru.key);
            }
            const node = new LruNode(key, value);
            this.map.set(key, node);
            this.addToHead(node);
        }
    }
}

export function lruCache(operations: number[]): number {
    const capacity = operations[0];
    const opCount = operations[1];
    const cache = new LruCacheImpl(capacity);
    let resultSum = 0;
    let idx = 2;

    for (let i = 0; i < opCount; i++) {
        const opType = operations[idx];
        const key = operations[idx + 1];
        const value = operations[idx + 2];
        idx += 3;

        if (opType === 1) {
            cache.put(key, value);
        } else if (opType === 2) {
            resultSum += cache.get(key);
        }
    }

    return resultSum;
}
